import React, { useEffect, useState } from "react";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  CartesianGrid,
} from "recharts";
import "../styles/MoodTracker.css";

const moodScore = {
  happy: 5,
  neutral: 3,
  sad: 2,
  angry: 1,
  anxious: 2,
};

const MoodTracker = () => {
  const [data, setData] = useState([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("moodHistory")) || [];

    // convert moods into graph-friendly data
    const formatted = stored.map((item, index) => ({
      day: `Day ${index + 1}`,
      mood: item.mood,
      score: moodScore[item.mood] || 3,
    }));

    setData(formatted);
  }, []);

  return (
    <div className="mood-page">
      <h1 className="mood-title">🧠 Mood Journey</h1>
      <p className="mood-subtitle">
        Your emotional history visualized beautifully
      </p>

      {data.length === 0 ? (
        <p className="no-mood">No mood data yet 🌱</p>
      ) : (
        <div className="chart-card">
          <ResponsiveContainer width="100%" height={320}>
            <AreaChart data={data}>
              <defs>
                <linearGradient id="moodGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#ffffff" stopOpacity={0.8} />
                  <stop offset="100%" stopColor="#ffffff" stopOpacity={0.1} />
                </linearGradient>
              </defs>

              <CartesianGrid strokeDasharray="3 3" opacity={0.2} />
              <XAxis dataKey="day" stroke="#fff" />
              <YAxis domain={[0, 5]} stroke="#fff" />
              <Tooltip />

              <Area
                type="monotone"
                dataKey="score"
                stroke="#ffffff"
                fill="url(#moodGradient)"
                strokeWidth={3}
                animationDuration={1200}
              />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
};

export default MoodTracker;
